const items = $input.all();
const now = new Date().toISOString();

const mindex = items[0]?.json || {};
const scraper = items[1]?.json || {};
const vectors = items[2]?.json || {};

const issues = [];

// Check MINDEX pipeline staleness
const lastRun = mindex.last_run ? new Date(mindex.last_run) : null;
if (lastRun) {
  const hoursSinceRun = (Date.now() - lastRun.getTime()) / (1000 * 60 * 60);
  if (hoursSinceRun > 26) {
    issues.push({
      pipeline: 'mindex',
      issue: 'stale',
      message: `MINDEX pipeline hasn't run in ${Math.round(hoursSinceRun)} hours`,
      severity: 'high'
    });
  }
}

// Check scraper errors
if (scraper.error_count > 10) {
  issues.push({
    pipeline: 'species_scraper',
    issue: 'high_errors',
    message: `${scraper.error_count} scraper errors in last cycle`,
    severity: 'medium'
  });
}

// Check if scraper is stuck
if (scraper.status === 'running' && scraper.running_since) {
  const runningHours = (Date.now() - new Date(scraper.running_since).getTime()) / (1000 * 60 * 60);
  if (runningHours > 4) {
    issues.push({
      pipeline: 'species_scraper',
      issue: 'stuck',
      message: `Scraper has been running for ${Math.round(runningHours)} hours — may be stuck`,
      severity: 'high'
    });
  }
}

// Check Qdrant collection health
const collections = vectors.collections || [];
for (const col of collections) {
  if (col.status === 'red') {
    issues.push({
      pipeline: 'qdrant',
      issue: 'collection_unhealthy',
      message: `Qdrant collection '${col.name}' is in RED status`,
      severity: 'critical'
    });
  }
}

const report = {
  timestamp: now,
  pipelines: {
    mindex: { status: mindex.status || 'unknown', last_run: mindex.last_run },
    scraper: { status: scraper.status || 'unknown', records_processed: scraper.records_processed || 0 },
    qdrant: { collections: (vectors.collections || []).length, status: vectors.status || 'unknown' }
  },
  issues: issues,
  has_issues: issues.length > 0,
  max_severity: issues.length > 0 ? issues.reduce((max, i) => {
    const levels = { critical: 4, high: 3, medium: 2, low: 1 };
    return (levels[i.severity] || 0) > (levels[max] || 0) ? i.severity : max;
  }, 'low') : 'none'
};

return [{ json: report }];
